import{_ as e,o as d,c as a,ae as s}from"./chunks/framework.BIONGpTb.js";const p=JSON.parse('{"title":"Filesystem Backend Consistency Audit","description":"","frontmatter":{},"headers":[],"relativePath":"internal/filesys-backend-audit.md","filePath":"internal/filesys-backend-audit.md"}'),o={name:"internal/filesys-backend-audit.md"};function r(i,t,n,c,l,h){return d(),a("div",null,[...t[0]||(t[0]=[s('<h1 id="filesystem-backend-consistency-audit" tabindex="-1">Filesystem Backend Consistency Audit <a class="header-anchor" href="#filesystem-backend-consistency-audit" aria-label="Permalink to &quot;Filesystem Backend Consistency Audit&quot;">​</a></h1><p>Audit of IndexedDB, FS Access API, OPFS, and WebDAV backends for behavioral and event-publishing consistency.</p><h2 id="backends" tabindex="-1">Backends <a class="header-anchor" href="#backends" aria-label="Permalink to &quot;Backends&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Backend</th><th>Path</th><th>Type</th></tr></thead><tbody><tr><td>IndexedDB</td><td><code>packages/core/src/core/filesys/indexeddb.ts</code></td><td>Local storage</td></tr><tr><td>FS Access API</td><td><code>packages/core/src/core/filesys/fs-access.ts</code></td><td>Local filesystem</td></tr><tr><td>OPFS</td><td><code>packages/core/src/core/filesys/opfs.ts</code></td><td>Wraps FS Access (same root)</td></tr><tr><td>WebDAV</td><td><code>packages/extension-webdav/src/webdav-filesys.ts</code></td><td>Remote</td></tr></tbody></table><h2 id="topic-workspace-changed-publishing" tabindex="-1">TOPIC_WORKSPACE_CHANGED Publishing <a class="header-anchor" href="#topic-workspace-changed-publishing" aria-label="Permalink to &quot;TOPIC_WORKSPACE_CHANGED Publishing&quot;">​</a></h2><p>Listeners use this event to refresh the file browser and other workspace-dependent UI.</p><table tabindex="0"><thead><tr><th>Operation</th><th>IDB</th><th>fs-access</th><th>WebDAV</th><th>OPFS</th></tr></thead><tbody><tr><td>File.saveContents</td><td>✓</td><td>✓ (fixed)</td><td>✓</td><td>inherits</td></tr><tr><td>File.delete</td><td>✓ (via self)</td><td>✓ (via parent)</td><td>✓</td><td>inherits</td></tr><tr><td>File.rename</td><td>✓</td><td>✓</td><td>✓</td><td>inherits</td></tr><tr><td>Directory.getResource (create)</td><td>✓</td><td>✓</td><td>✓</td><td>inherits</td></tr><tr><td>Directory.delete</td><td>✓</td><td>✓</td><td>✓</td><td>inherits</td></tr><tr><td>Directory.rename</td><td>✓</td><td>✓</td><td>✓</td><td>inherits</td></tr><tr><td>Directory.touch</td><td>✓</td><td>✓</td><td>✓</td><td>inherits</td></tr></tbody></table><p><strong>Fix applied:</strong> <code>FileSysFileHandleResource.saveContents</code> was missing the publish; added to match IDB and WebDAV.</p><h2 id="path-normalization" tabindex="-1">Path Normalization <a class="header-anchor" href="#path-normalization" aria-label="Permalink to &quot;Path Normalization&quot;">​</a></h2><p><code>getResource</code> path handling:</p><table tabindex="0"><thead><tr><th>Backend</th><th>Segment handling</th><th>Example <code>&quot;a//b&quot;</code></th></tr></thead><tbody><tr><td>IDB</td><td><code>path.split(&#39;/&#39;).filter(s =&gt; s.trim())</code></td><td><code>[&quot;a&quot;,&quot;b&quot;]</code></td></tr><tr><td>fs-access</td><td>previously <code>split(&quot;/&quot;)</code> + <code>break</code> on empty</td><td><code>[&quot;a&quot;]</code> (bug)</td></tr><tr><td>WebDAV</td><td><code>path.split(&quot;/&quot;).filter(s =&gt; s.trim())</code></td><td><code>[&quot;a&quot;,&quot;b&quot;]</code></td></tr></tbody></table><p><strong>Fix applied:</strong> fs-access now uses <code>path.split(&quot;/&quot;).filter(s =&gt; s.trim())</code> to align with IDB and WebDAV.</p><h2 id="file-vs-directory-descend-logic" tabindex="-1">File- vs Directory-Descend Logic <a class="header-anchor" href="#file-vs-directory-descend-logic" aria-label="Permalink to &quot;File- vs Directory-Descend Logic&quot;">​</a></h2><p>When resolving a path, if an intermediate segment is a file (not a directory), further descent is invalid.</p><table tabindex="0"><thead><tr><th>Backend</th><th>Behavior</th></tr></thead><tbody><tr><td>IDB</td><td><code>if (entry.type !== &#39;dir&#39;) return null</code> before descending</td></tr><tr><td>fs-access</td><td>Previously no check; would return the file when more segments remained</td></tr><tr><td>WebDAV</td><td>Uses <code>children</code>, only adds dirs when creating; files block descent implicitly</td></tr></tbody></table><p><strong>Fix applied:</strong> fs-access now returns <code>null</code> when <code>currentResource</code> is not <code>FileSysDirHandleResource</code> and more segments remain (<code>} else { return null; }</code>).</p><h2 id="publish-patterns" tabindex="-1">Publish Patterns <a class="header-anchor" href="#publish-patterns" aria-label="Permalink to &quot;Publish Patterns&quot;">​</a></h2><ul><li><strong>IDB:</strong> Publishes at end of each mutating method (delete, saveContents, rename, getResource create, touch).</li><li><strong>fs-access:</strong> Uses <code>try/finally</code> in <code>getResource</code> so publish runs even on early return; other methods publish at end.</li><li><strong>WebDAV:</strong> Publishes at end of each mutating method; <code>getResource</code> publishes when <code>workspaceChanged</code>.</li></ul><p>All backends now follow a consistent pattern.</p>',19)])])}const b=e(o,[["render",r]]);export{p as __pageData,b as default};
